iv class="nav"><div><h1>Owner Center</h1><p class="muted">Hanya user ID 1 boleh akses. Edit store, QRIS, plan dan order.</p></div><div><a class="btn" href="/">Store</a> <a class="btn" href="/admin">Admin</a></div></div>@if(session('pahri_success'))<div class="alert">{{ session('pahri_success') }}</div>@endif<div class="grid"><section class="card"><h2>Website Store & QRIS</h2><form method="POST" action="/owner">@csrf<label>Nama Store</label><input name="store_name" value="{{ $store['store_name'] ?? 'Pahri Panel Store' }}" required><label>Tagline</label><input name="tagline" value="{{ $store['tagline'] ?? '' }}"><label>Currency</label><select name="currency"><option value="IDR" @selected(($store['currency']??'IDR')==='IDR')>IDR</option><option value="MYR" @selected(($store['currency']??'IDR')==='MYR')>MYR</option><option value="USD" @selected(($store['currency']??'IDR')==='USD')>USD</option></select><label>WhatsApp</label><input name="whatsapp" value="{{ $store['whatsapp'] ?? '' }}"><label>QRIS Endpoint</label><input name="qris_endpoint" value="{{ $store['qris_endpoint'] ?? 'https://qris.zakki.store' }}" required><label>QRIS Merchant ID</label><input name="qris_merchant_id" value="{{ $store['qris_merchant_id'] ?? '' }}"><label>QRIS API Key / Token</label><input type="password" name="qris_api_key" placeholder="Kosongkan kalau tak mahu tukar token"><p class="muted">Token tersimpan: {{ $secrets['has_api_key'] ? 'YA' : 'BELUM' }} @if($secrets['updated_at'])• update {{ $secrets['updated_at'] }}@endif</p><label><input type="checkbox" name="qris_clear_key" value="1" style="width:auto;min-height:auto"> Clear token tersimpan</label><h3>Plans</h3>@for($i=0;$i<6;$i++)@php($p=$plans[$i]??['name'=>'','ram_gb'=>'','price'=>'','description'=>''])<div class="order"><label>Plan {{ $i+1 }} Name</label><input name="plan_name[]" value="{{ $p['name'] }}" @if($i<3) required @endif><label>RAM GB</label><input type="number" name="plan_ram[]" value="{{ $p['ram_gb'] }}" @if($i<3) required @end